import React, { useState, useEffect, useRef } from 'react';

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);
  const [isClick, setIsClick] = useState(true);
  const sensitivity = 2;
  const socketRef = useRef(null);

  useEffect(() => {
    // Inițializăm conexiunea WebSocket
    const ws = new WebSocket('ws://localhost:8000/ws/mouse/');
    ws.onopen = () => {
      console.log('WebSocket connection opened');
    };

    ws.onclose = () => {
      console.log('WebSocket connection closed');
    };

    ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    socketRef.current = ws;

    return () => {
      // Închidem conexiunea la demontarea componentei
      ws.close();
    };
  }, []);

  const sendMouseMove = (deltaX, deltaY) => {
    if (socketRef.current && socketRef.current.readyState === WebSocket.OPEN) {
      socketRef.current.send(JSON.stringify({ action: 'move', x: deltaX, y: deltaY }));
    }
  };

  const sendMouseClick = (button = 'left', double = false) => {
    if (socketRef.current && socketRef.current.readyState === WebSocket.OPEN) {
      socketRef.current.send(JSON.stringify({ action: 'click', button: button, double: double }));
    }
  };

  const handleTouchStart = (event) => {
    const touch = event.touches[0];
    setStartTouch({ x: touch.clientX, y: touch.clientY });
    setIsClick(true);
  };

  const handleTouchMove = (event) => {
    event.preventDefault();
    const touch = event.touches[0];

    if (startTouch) {
      const deltaX = (touch.clientX - startTouch.x) * sensitivity;
      const deltaY = (touch.clientY - startTouch.y) * sensitivity;

      if (Math.abs(deltaX) > 5 || Math.abs(deltaY) > 5) {
        setIsClick(false);
      }

      sendMouseMove(deltaX, deltaY);
      setStartTouch({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    if (isClick) {
      sendMouseClick('left');
    }
    setStartTouch(null);
  };

  return (
    <div
      className="touchpad-container"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      <h2>Touchpad Controller</h2>
      <p>Use the touchpad to move the mouse and tap to click.</p>
    </div>
  );
};

export default Keyboard_mouse;
